              c.findAll(MethodDeclaration.class).stream()
               .filter(m -> m.getNameAsString().equals("getStream") || m.getNameAsString().equals("thresholdReached"))
               .forEach(m -> m.getAnnotations().removeIf(a -> a.getNameAsString().equals("Override")));

