@Override
public void write(int b) throws IOException {
    if (closed) {
        throw new IOException("Stream is closed");
    }
    if (getStream() == memoryOutputStream && memoryOutputStream.size() >= threshold) {
        thresholdReached();
    }
    getStream().write(b);
}

