    if (closed) {
        throw new IOException("Stream is closed");
    }
    if (getStream() == memoryOutputStream && memoryOutputStream.size() + len > threshold) {
        thresholdReached();
    }
    getStream().write(b, off, len);
}

@Override
public void write(byte[] b) throws IOException {
    write(b, 0, b.length);
}

@Override
public void flush() throws IOException {
    getStream().flush();
}

